--- a/src/frontend/dashboard/product_live_data.js
+++ b/src/frontend/dashboard/product_live_data.js
@@ -1,5 +1,6 @@
 function fetchDiagnoseData(productId) {
-  return axios.post(`/product/live-data/diagnose`, { productId }, { timeout: 8000 })
-    .then(response => response.data)
-    .catch(error => { throw new Error('Diagnose request failed'); });
+  const pollInterval = 2000;
+  const maxRetries = 15;
+  return axios.post(`/product/live-data/diagnose`, { productId }, { timeout: 10000 })
+    .then(response => {
+      if (response.status === 202) {
+        const taskId = response.data.task_id;
+        return pollResult(taskId, 0);
+      }
+      return response.data;
+    })
+    .catch(error => { throw new Error('Diagnose initiation failed'); });
+
+  function pollResult(taskId, attempt) {
+    return axios.get(`/tasks/status/${taskId}`)
+      .then(res => {
+        if (res.data.status === 'SUCCESS') return res.data.result;
+        if (attempt >= maxRetries) throw new Error('Diagnose timed out after polling');
+        return new Promise(resolve => setTimeout(() => resolve(pollResult(taskId, attempt+1)), pollInterval));
+      });
+  }
 }
